segment.target:
{version, select,
        1 {Les arbustes de la zone ne contiennent aucun fruit, vous n'êtes pas tombé à la bonne saison, il faudra revenir plus tard !}
        other {Après plusieurs heures passées à récolter de petits fruits noirs, vous vous apercevez que ceux-ci se sont ouverts et que leur contenu a détalé hors de vos sacs !}}

{version, select,
        1 {À part le vent qui balaie la plaine, il n'y a strictement rien à signaler dans cette zone.}
        other {Rien d'autre que le vent qui agite la poussière.}}

{version, select,
        1 {Un grand volcan trône au milieu de cette zone, à votre niveau de grands jets de vapeurs hantent le paysage. Une odeur de soufre brûle vos narines…}
        other {De très bucoliques rivières de lave traversent paisiblement la région.}}

{version, select,
        1 {Avec surprise, vous découvrez que cette étendue désertique ne contient absolument aucun élément permettant d'améliorer votre situation.}
        other {Ce désert est désespérément vide… Personne à l'horizon…}}

{version, select, 
        1 {De violents vents agitent l'océan. C'est un temps idéal pour faire du surf, mais vous devez sauver l'humanité...}
        other {La mer est calme. Rien d'intéressant par ici.}}

{equipment_first_letter, select,
        vowel {La pompe d'oxygène de {equipment} est enrayée, il n'y a rien à en tirer !}
        consonant {La pompe d'oxygène du {equipment} est enrayée, il n'y a rien à en tirer !}
        other {La pompe d'oxygène du {equipment} est enrayée, il n'y a rien à en tirer !}
        }

{quantity, plural,
        one {Tous les équipiers subissent # point de dégâts.}
        other {Tous les équipiers subissent # points de dégâts.}
        }{skill_reduced_damage_for_player}

{character_gender, select,
        male {{equipment} atterit en catastrophe sur {planet}, durant la manoeuvre, {character} est blessé !}
        female {{equipment} atterit en catastrophe sur {planet}, durant la manoeuvre, {character} est blessée !}
        other {{equipment} atterit en catastrophe sur {planet}, durant la manoeuvre, {character} est blessé.e !}
        }

{quantity, select,
        8 {La pompe d'oxygène de {equipment} est prête à rendre l'âme, elle aspire péniblement {quantity} m³ d'oxygène.}
        16 {Vous lancez une opération de pompage d'oxygène afin de remplir les réserves du Daedalus. Apparemment la pompe de {equipment} n'est plus toute jeune… Hop, {quantity} m³ d'oxygène !}
        24 {Vous lancez une opération de pompage d'oxygène afin de remplir les réserves du Daedalus. Tout se passe à merveille, vous avez récupéré {quantity} m³ d'oxygène !}
        other {Vous lancez une opération de pompage d'oxygène afin de remplir les réserves du Daedalus. Vous récupérez {quantity} m³ d'oxygène !}
        }

{has_drill, select,
          true {{quantity, select,
        6 {Au fond d'une crevasse, vous tombez sur une jolie veine de charbonite…}
        8 {Les grosses flaques de boues semblent contenir des traces de goudron supercarboné, il faut en récupérer un peu pour le Daedalus.}
        10 {Incroyable ! L'expédition vient de découvrir un gigantesque monolithe de charbonite ! Il ne rentrera jamais dans le réacteur…}
        12 {L'expédition trouve un petit lac d'heptanol violacé ! Avec tout ça le Daedalus n'est pas près de tomber en panne !}
        other {Vous récupérez {quantity} unités de fuel.}}}
          other {{quantity, select,
        3 {Au fond d'une crevasse, vous tombez sur une jolie veine de charbonite…}
        4 {Les grosses flaques de boues semblent contenir des traces de goudron supercarboné, il faut en récupérer un peu pour le Daedalus.}
        5 {Incroyable ! L'expédition vient de découvrir un gigantesque monolithe de charbonite ! Il ne rentrera jamais dans le réacteur…}
        6 {L'expédition trouve un petit lac d'heptanol violacé ! Avec tout ça le Daedalus n'est pas près de tomber en panne !}
        other {Vous récupérez {quantity} unités de fuel.}}}
        }

{target_equipment_gender, select,
        male {Derrière un rocher, vous trouvez une créature étrange très affaiblie. Vous lui donnez un peu d'eau afin qu'elle reprenne connaissance. La créature vous offre un {target_equipment} avant de reprendre sa route.}
        female {Derrière un rocher, vous trouvez une créature étrange très affaiblie. Vous lui donnez un peu d'eau afin qu'elle reprenne connaissance. La créature vous offre une {target_equipment} avant de reprendre sa route.}
        other {Derrière un rocher, vous trouvez une créature étrange très affaiblie. Vous lui donnez un peu d'eau afin qu'elle reprenne connaissance. La créature vous offre un {target_equipment} avant de reprendre sa route.}
        }

{quantity, select,
        2 {Vous rencontrez une myriade de petits rongeurs. Dans la panique générale vous parvenez à attraper l'un d'entre eux.}
        4 {Vous chassez avec succès un Chab Chab... Vous récupérez de la viande alien.}
        other {Vous chassez avec succès un Chab Chab... Vous récupérez de la viande alien.}
        }

{quantity, select, 
        1 {Plusieurs arbustes touffus attirent votre attention, dans l'un d'entre eux se trouve de curieux fruits…}
        3 {Vous trouvez un arbre géant similaire à un baobab. À son sommet pousse une multitude de fruits étranges que vous décidez de ramener au Daedalus.}
        other {Plusieurs arbustes touffus attirent votre attention, dans l'un d'entre eux se trouve de curieux fruits…}
        }

{character_gender, select,
        male {Malgré les recherches, vous n'avez trouvé aucune trace de {character}. Pourtant il doit bien être quelque part !}
        female {Malgré les recherches, vous n'avez trouvé aucune trace de {character}. Pourtant elle doit bien être quelque part !}
        other {Malgré les recherches, vous n'avez trouvé aucune trace de {character}. Pourtant iel doit bien être quelque part !}}

{equipment_gender, select,
        male {Un être étrange tente de rentrer en contact avec vous, il inspecte chacun d'entre vous puis s'empare d'un {equipment} appartenant à {character} et s'enfuit à grandes enjambées.}
        female {Un être étrange tente de rentrer en contact avec vous, il inspecte chacun d'entre vous puis s'empare d'une {equipment} appartenant à {character} et s'enfuit à grandes enjambées.}
        other {Un être étrange tente de rentrer en contact avec vous, il inspecte chacun d'entre vous puis s'empare d'un {equipment} appartenant à {character} et s'enfuit à grandes enjambées.}}

{equipment_gender, select,
        male {Le vent souffle si fort que {character} laisse échapper un {equipment} ! On est pas près de le retrouver…}
        female {Le vent souffle si fort que {character} laisse échapper une {equipment} ! On est pas près de la retrouver…}
        other {Le vent souffle si fort que {character} laisse échapper un {equipment} ! On est pas près de le retrouver…}}

{character_gender, select,
        male {Grosse galère... {character} est tombé à l'eau. Ça va complexifier la suite des opérations...}
        female {Grosse galère... {character} est tombée à l'eau. Ça va complexifier la suite des opérations...}
        other {Grosse galère... {character} vient de tomber à l'eau. Ça va complexifier la suite des opérations...}
        }

{character, select,
Terrence {Vous entendez des jurons au loin et vous vous rapprochez en restant sur vos gardes. Vous finissez par tomber sur {character} en train de réparer sa chaise après des heures à rouler dans la boue !}
other {{version, select,
        1 {Vous avez trouvé des traces de pas humaines !!! En les suivant vous tombez sur {character}. Quelle déception…}
        other {Alors que vous vous apprêtiez à quitter la zone, vous entendez des cris derrière vous. Il s'agit de {character} qui court après vous en hurlant depuis plus d'une heure. Ses vêtements sont tout déchirés !}
        }}
}

{character_gender, select,
        male  {Vous avez trouvé {character} derrière un rocher ! Malheureusement, il ne bouge plus du tout. D'ailleurs, il n'a pas l'air de respirer non plus. A tous les coups, les gars du labo vont vous dire qu'il est mort…}
        female {Vous avez trouvé {character} derrière un rocher ! Malheureusement, elle ne bouge plus du tout. D'ailleurs, elle n'a pas l'air de respirer non plus. A tous les coups, les gars du labo vont vous dire qu'elle est morte…}
        other {Vous avez trouvé {character} derrière un rocher ! Malheureusement, iel ne bouge plus du tout. D'ailleurs, iel n'a pas l'air de respirer non plus. A tous les coups, les gars du labo vont vous dire qu'iel a péri…}}
